 3→const PromptSection = ({ prompt, responsesData, onWriteResponse }) => {
 4→    const responseCount = responsesData?.count || 0;
 5→    const avatars = (responsesData?.responses || []).slice(0, 5);
 6→
 7→    return (
 8→        <div className="dashboard-prompt">
 9→            <div className="dashboard-prompt-header">
10→                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 -960 960 960" fill="currentColor" className="dashboard-prompt-icon">
11→                    <path d="M480-80q-26 0-47-12.5T400-126q-33 0-56.5-23.5T320-206v-142q-59-39-94.5-103T190-590q0-121 84.5-205.5T480-880q121 0 205.5 84.5T770-590q0 77-35.5 140T640-348v142q0 33-23.5 56.5T560-126q-12 21-33 33.5T480-80Zm-80-126h160v-36H400v36Zm0-76h160v-38H400v38Zm-8-118h58v-108l-88-88 42-42 76 76 76-76 42 42-88 88v108h58q54-26 88-76.5T690-590q0-88-61-149t-149-61q-88 0-149 61t-61 149q0 63 34 113.5t88 76.5Z"/>
12→                </svg>
13→                <span className="dashboard-prompt-label">Today's Prompt</span>
14→                {prompt.category && (
15→                    <span className="dashboard-prompt-category">{prompt.category}</span>
16→                )}
17→            </div>
18→            <p className="dashboard-prompt-text">{prompt.prompt_text}</p>
19→            <div className="dashboard-prompt-footer">
20→                <button
21→                    className="dashboard-prompt-write-btn"
22→                    onClick={() => onWriteResponse?.(prompt)}
23→                >
24→                    Write your take <span style={{ marginLeft: '6px' }}>→</span>
25→                </button>
26→                {responseCount > 0 && (
27→                    <div className="dashboard-prompt-responses">
28→                        <div className="dashboard-prompt-avatars">
29→                            {avatars.map((r, i) => (
30→                                <img
31→                                    key={r.id}
32→                                    src={r.users?.image_url || '/assets/profile.jpg'}
33→                                    alt=""
34→                                    className="dashboard-prompt-avatar"
35→                                    style={{ zIndex: avatars.length - i }}
36→                                />
37→                            ))}
38→                        </div>
39→                        <span className="dashboard-prompt-count">
40→                            {responseCount} {responseCount === 1 ? 'response' : 'responses'}
41→                        </span>
42→                    </div>
43→                )}
44→            </div>
45→        </div>
46→    );
47→};
48→
49→export default PromptSection;
