 1→import React from 'react';
 2→import { motion } from 'framer-motion';
 3→import { useNavigate } from 'react-router-dom';
 4→
 5→const StarIcon = () => (
 6→    <svg width="14" height="14" viewBox="0 0 24 24" fill="currentColor">
 7→        <path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z"/>
 8→    </svg>
 9→);
