11→const BestPostCard = ({ bestPost }) => {
12→    const navigate = useNavigate();
13→
14→    if (!bestPost || !bestPost.journal_id) return null;
15→
16→    const handleClick = () => {
17→        navigate(`/home/post/${bestPost.journal_id}`);
18→    };
19→
20→    return (
21→        <motion.div
22→            className="recap-best-post"
23→            initial={{ opacity: 0, y: 14 }}
24→            animate={{ opacity: 1, y: 0 }}
25→            transition={{ duration: 0.35, delay: 0.45, ease: 'easeOut' }}
26→            onClick={handleClick}
27→            role="button"
