    display: flex;
    align-items: center;
    gap: 8px;
}

.dashboard-prompt-avatars {
    display: flex;
}

.dashboard-prompt-avatar {
    width: 24px;
    height: 24px;
    border-radius: 50%;
    border: 2px solid var(--bg-card, #fefefe);
    margin-left: -8px;  /* overlapping stacked effect */
    object-fit: cover;
}

.dashboard-prompt-avatar:first-child {
